function Particles() {
  const pts = Array.from({length:18},(_,i)=>({
    w:(Math.random()*3+1)+"px", l:(Math.random()*100)+"%",
    top:(Math.random()*100)+"%",
    dur:(Math.random()*14+10)+"s", del:-(Math.random()*20)+"s",
    op:Math.random()*0.5+0.2
  }));
  return (
    <div style={{position:"absolute",inset:0,overflow:"hidden",pointerEvents:"none",zIndex:0}}>
      {pts.map((p,i)=>(
        <div key={i} style={{
          position:"absolute",borderRadius:"50%",
          width:p.w,height:p.w,left:p.l,top:p.top,opacity:p.op,
          background:"radial-gradient(circle,rgba(0,183,255,0.8) 0%,transparent 70%)",
          animation:`ptFloat ${p.dur} linear ${p.del} infinite`
        }}/>
      ))}
    </div>
  );
}

